1	export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	
3	export type Customer = { yearsWithMHPCO: number };
4	
5	export type Damage = { itemType: string; amount: number };
6	
7	export type Incident = { cause?: string; damages: Damage[] };
8	
9	export type Step = {
10	  op: string;
11	  items?: Item[];
12	  policy?: number;
13	  incident?: Incident;
14	};
15	
16	export type Scenario = {
17	  customer: Customer;
18	  steps: Step[];
19	};
20	
21	export type ScenarioResult = {
22	  results: StepResult[];
23	};
24	
25	const PROCESSING_FEE = 5;
26	
27	const BASE_PREMIUMS: Record<string, number> = {
28	  sword: 100,
29	  amulet: 60,
30	  staff: 80,
31	  potion: 40,
32	  rune: 25,
33	  moonstone: 25,
34	};
35	
36	const INSURANCE_VALUES: Record<string, number> = {
37	  sword: 1000,
38	  amulet: 600,
39	  staff: 800,
40	  potion: 400,
41	  rune: 250,
42	  moonstone: 250,
43	};
44	
45	const DEDUCTIBLE = 100;
46	const CAP_MULTIPLIER = 2;
47	const PAYOUT_HIGH_ENCHANTMENT_THRESHOLD = 8;
48	const PAYOUT_HIGH_ENCHANTMENT_RATE = 0.5;
49	
50	type StepResult = { premium?: number; payout?: number; remainingCap?: number };
51	
52	const BLOCK_SIZE = 3;
53	const BLOCK_PREMIUM = 60;
54	
55	const CURSE_SURCHARGE_RATE = 0.5;
56	const FIRST_INSURANCE_RATE = 0.1;
57	const HIGH_ENCHANTMENT_RATE = 0.3;
58	const HIGH_ENCHANTMENT_THRESHOLD = 5;
59	const LOYALTY_DISCOUNT_RATE = 0.2;
60	const LOYALTY_YEARS_THRESHOLD = 2;
61	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
62	
63	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
64	
65	const isKnownItemType = (type: string): boolean => type in BASE_PREMIUMS;
66	
67	const assertKnownItemTypes = (items: Item[]): void => {
68	  for (const item of items) {
69	    if (!isKnownItemType(item.type)) {
70	      throw new Error(`unknown item type: ${item.type}`);
71	    }
72	  }
73	};
74	
75	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
76	
77	const groupKeyFor = (item: Item, index: number): string =>
78	  COMPONENT_TYPES.has(item.type) ? item.type : `item:${index}`;
79	
80	const groupItemsForPricing = (items: Item[]): Item[][] => {
81	  const groups = new Map<string, Item[]>();
82	  items.forEach((item, index) => {
83	    const key = groupKeyFor(item, index);
84	    const group = groups.get(key) ?? [];
85	    group.push(item);
86	    groups.set(key, group);
87	  });
88	  return [...groups.values()];
89	};
90	
91	const premiumForGroup = (group: Item[]): number =>
92	  group.length === BLOCK_SIZE
93	    ? BLOCK_PREMIUM
94	    : group.reduce((total, item) => total + basePremiumFor(item), 0);
95	
96	const totalBasePremiumFor = (items: Item[]): number =>
97	  groupItemsForPricing(items).reduce((total, group) => total + premiumForGroup(group), 0);
98	
99	const itemSurchargeFor = (
100	  items: Item[],
101	  qualifies: (item: Item) => boolean,
102	  rate: number,
103	): number =>
104	  items.reduce(
105	    (total, item) => (qualifies(item) ? total + basePremiumFor(item) * rate : total),
106	    0,
107	  );
108	
109	const isCursed = (item: Item): boolean => item.cursed === true;
110	
111	const isHighlyEnchanted = (item: Item): boolean =>
112	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
113	
114	type QuoteContext = { customer: Customer; quoteIndex: number };
115	
116	type PolicyModifier = (base: number, items: Item[], context: QuoteContext) => number;
117	
118	const discountWhen =
119	  (rate: number, qualifies: (context: QuoteContext) => boolean): PolicyModifier =>
120	  (base, _items, context) =>
121	    qualifies(context) ? -(base * rate) : 0;
122	
123	const isLoyalCustomer = ({ customer }: QuoteContext): boolean =>
124	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
125	
126	const isFollowUpQuote = ({ quoteIndex }: QuoteContext): boolean => quoteIndex > 0;
127	
128	const cursedSurcharge: PolicyModifier = (_base, items) =>
129	  itemSurchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
130	
131	const highEnchantmentSurcharge: PolicyModifier = (_base, items) =>
132	  itemSurchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_RATE);
133	
134	const firstInsuranceSurcharge: PolicyModifier = (base) => base * FIRST_INSURANCE_RATE;
135	
136	const loyaltyDiscount = discountWhen(LOYALTY_DISCOUNT_RATE, isLoyalCustomer);
137	
138	const followUpDiscount = discountWhen(FOLLOW_UP_DISCOUNT_RATE, isFollowUpQuote);
139	
140	const POLICY_MODIFIERS: PolicyModifier[] = [
141	  cursedSurcharge,
142	  highEnchantmentSurcharge,
143	  firstInsuranceSurcharge,
144	  loyaltyDiscount,
145	  followUpDiscount,
146	];
147	
148	const sumModifiers = (base: number, items: Item[], context: QuoteContext): number =>
149	  POLICY_MODIFIERS.reduce((total, modifier) => total + modifier(base, items, context), 0);
150	
151	const quotePremium = (items: Item[], context: QuoteContext): number => {
152	  assertKnownItemTypes(items);
153	  const base = totalBasePremiumFor(items);
154	  return Math.ceil(base + sumModifiers(base, items, context) + PROCESSING_FEE);
155	};
156	
157	const insuranceValueFor = (item: Item): number => INSURANCE_VALUES[item.type] ?? 0;
158	
159	const insuranceSumOf = (items: Item[]): number =>
160	  items.reduce((sum, item) => sum + insuranceValueFor(item), 0);
161	
162	const policyItemsFor = (step: Step, scenario: Scenario): Item[] =>
163	  scenario.steps[step.policy ?? 0].items ?? [];
164	
165	const damagesIn = (step: Step): Damage[] => step.incident?.damages ?? [];
166	
167	const insuredItemFor = (damage: Damage, items: Item[]): Item | undefined =>
168	  items.find((item) => item.type === damage.itemType);
169	
170	const triggersPartialPayout = (item: Item | undefined): boolean =>
171	  (item?.enchantment ?? 0) >= PAYOUT_HIGH_ENCHANTMENT_THRESHOLD;
172	
173	const reimbursableAmount = (damage: Damage, item: Item | undefined): number =>
174	  triggersPartialPayout(item) ? damage.amount * PAYOUT_HIGH_ENCHANTMENT_RATE : damage.amount;
175	
176	const payoutForDamage = (damage: Damage, items: Item[]): number =>
177	  Math.max(0, reimbursableAmount(damage, insuredItemFor(damage, items)) - DEDUCTIBLE);
178	
179	const totalPayoutFor = (damages: Damage[], items: Item[]): number =>
180	  damages.reduce((total, damage) => total + payoutForDamage(damage, items), 0);
181	
182	const processClaim = (
183	  step: Step,
184	  scenario: Scenario,
185	  alreadyPaid: number,
186	): { result: StepResult; paid: number } => {
187	  const policyItems = policyItemsFor(step, scenario);
188	  const cap = CAP_MULTIPLIER * insuranceSumOf(policyItems);
189	  const desired = totalPayoutFor(damagesIn(step), policyItems);
190	  const payout = Math.min(desired, cap - alreadyPaid);
191	  return { result: { payout, remainingCap: cap - alreadyPaid - payout }, paid: alreadyPaid + payout };
192	};
193	
194	type RunState = { results: StepResult[]; paidByPolicy: Map<number, number> };
195	
196	const withPaid = (
197	  paidByPolicy: Map<number, number>,
198	  policyIndex: number,
199	  paid: number,
200	): Map<number, number> => new Map(paidByPolicy).set(policyIndex, paid);
201	
202	const appendResult = (state: RunState, result: StepResult): RunState => ({
203	  ...state,
204	  results: [...state.results, result],
205	});
206	
207	const handleClaim = (state: RunState, step: Step, scenario: Scenario): RunState => {
208	  const policyIndex = step.policy ?? 0;
209	  const alreadyPaid = state.paidByPolicy.get(policyIndex) ?? 0;
210	  const { result, paid } = processClaim(step, scenario, alreadyPaid);
211	  return {
212	    results: [...state.results, result],
213	    paidByPolicy: withPaid(state.paidByPolicy, policyIndex, paid),
214	  };
215	};
216	
217	const handleQuote = (
218	  state: RunState,
219	  step: Step,
220	  scenario: Scenario,
221	  quoteIndex: number,
222	): RunState =>
223	  appendResult(state, {
224	    premium: quotePremium(step.items ?? [], { customer: scenario.customer, quoteIndex }),
225	  });
226	
227	const processStep = (
228	  state: RunState,
229	  step: Step,
230	  scenario: Scenario,
231	  quoteIndex: number,
232	): RunState =>
233	  step.op === "claim"
234	    ? handleClaim(state, step, scenario)
235	    : handleQuote(state, step, scenario, quoteIndex);
236	
237	export const runScenario = (scenario: Scenario): ScenarioResult => {
238	  const initial: RunState = { results: [], paidByPolicy: new Map() };
239	  const final = scenario.steps.reduce(
240	    (state, step, index) => processStep(state, step, scenario, index),
241	    initial,
242	  );
243	  return { results: final.results };
244	};
